import { FieldPacket, QueryResult } from 'mysql2/typings/mysql/lib/protocol/packets';
import { QueryOptions, QueryableConstructor, ExecuteValues } from 'mysql2/typings/mysql/lib/protocol/sequences/Query.js';

export declare function ExecutableBase<T extends QueryableConstructor>(
  Base?: T
): {
  new (...args: any[]): {
    execute<T extends QueryResult>(
      sql: string,
      values?: ExecuteValues
    ): Promise<[T, FieldPacket[]]>;
    execute<T extends QueryResult>(
      options: QueryOptions,
      values?: ExecuteValues
    ): Promise<[T, FieldPacket[]]>;
  };
} & T;
